const Q_BIOLOGY_2014=[{"id": "objective>Biology>2014>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What subject is this?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Biology</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Physics</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Chemistry</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mathematics</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The subject is indicated in the id of the question. The id is 'objective>Biology>2014>1', which means the subject is Biology.</div>", "topic": "LIVING ORGANISMS : CHARACTERISTICS"}, {"id": "objective>Biology>2014>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question that follows  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The part labelled II is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">eyespot</div>", "<div style=\"font-family:Cambria;font-size:17px;\">basal granule</div>", "<div style=\"font-family:Cambria;font-size:17px;\">contractile vacuole</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nucleus</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Contractile vacuoles protect a cell from absorbing too much water and potentially exploding by excreting excess water.</div>", "topic": "LIVING ORGANISMS : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS"}, {"id": "objective>Biology>2014>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer the question that follows  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The part responsible for photosynthesis is labelled</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The part responsible for Photosynthesis is the part labelled III. The part labelled III is the chloroplast</div>", "topic": "NUTRITION : PHOTOSYNTHESIS"}, {"id": "objective>Biology>2014>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The lowest level of organization in living organisms is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cell</div>", "<div style=\"font-family:Cambria;font-size:17px;\">system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tissue</div>", "<div style=\"font-family:Cambria;font-size:17px;\">organ</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The lowest level of organization in living organisms is the cell. This is a basic concept in biology. Organisms are made up of cells, which form tissues, tissues form organs, and organs form systems.</div>", "topic": "LIVING ORGANISMS : LEVEL OF ORGANIZATION"}, {"id": "objective>Biology>2014>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is the most complex according to their cellular level of organization?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Hair</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Euglena</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hydra</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Heart</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The heart is the most complex according to their cellular level of organization. The heart is an organ, which is made up of tissues, and tissues are made up of cells. The other options, Hair (made up of cells), Euglena (a single-celled organism), and Hydra (a multicellular organism but less complex than an organ like the heart), are less complex in their cellular organization.</div>", "topic": "LIVING ORGANISMS : LEVEL OF ORGANIZATION"}, {"id": "objective>Biology>2014>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question that follows.  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The organs for attachment to the lining of the host's intestine are labelled</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">III and IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">l and II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">l and III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and III</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">II and III are the hooks and suckers with it use to attach firmly to the intestinal wall of its host.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>2014>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer the question that follows.  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The young proglottid is represented by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The young proglottid is represented by IV. A young proglottid in a tapeworm is a small, developing segment located near the neck of the worm. It has immature reproductive organs and is characterized by high cellular activity and growth. As it matures, it moves toward the posterior end, eventually developing fully functional reproductive organs and becoming gravid with eggs.</div>", "topic": "HEREDITY : CHROMOSOMES"}, {"id": "objective>Biology>2014>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following organisms is multicellular?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Spirogyra</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Amoeba</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Euglena</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Chlamydomonas</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Spirogyra is multicellular while amoeba, euglena and chlamydomonas are unicellular.</div>", "topic": "LIVING ORGANISMS : CHARACTERISTICS"}, {"id": "objective>Biology>2014>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In bryophytes, sex organs are produced in the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sporophyte</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gametophyte</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rhizoid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">protonema</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In bryophytes, sex organs are produced in the gametophyte. Bryophytes are non-vascular plants, such as mosses and liverworts. They have a life cycle that alternates between a haploid gametophyte stage and a diploid sporophyte stage. The gametophyte stage is dominant and is the stage during which the sex organs, the archegonia (female) and antheridia (male), are produced.</div>", "topic": "REPRODUCTION : SEXUAL REPRODUCTION"}, {"id": "objective>Biology>2014>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Seed plants are the most dominant vegetation on land because of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">their ability to photosynthesize</div>", "<div style=\"font-family:Cambria;font-size:17px;\">efficient seed dispersal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">availability of water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">their motile gametes</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Seed plants are the most dominant vegetation on land because of their efficient seed dispersal. Seed plants, which include gymnosperms and angiosperms, have developed a variety of mechanisms for seed dispersal, such as wind, water, and animals. This allows them to colonize a wide range of habitats. While the ability to photosynthesize, availability of water, and motile gametes are important for plant life, they are not the primary reasons why seed plants are the most dominant vegetation on land.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>2014>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is an aboreal organism?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Fish</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Antelope</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Bird</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Elephant</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An arboreal organism is an organism that lives in or among trees. Birds are a perfect example of arboreal organisms as they spend most of their time in trees.</div>", "topic": "NATURAL HABITAT : AQUATIC TERRESTRIAL AND ARBOREAL"}, {"id": "objective>Biology>2014>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question that follows.  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The part labelled I is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">phloem</div>", "<div style=\"font-family:Cambria;font-size:17px;\">root hair</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cortex</div>", "<div style=\"font-family:Cambria;font-size:17px;\">xylem</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The part labelled I in the diagram is the root hair.</div>", "topic": "INTERNAL STRUCTURE OF A FLOWERING PLANT : ROOT"}, {"id": "objective>Biology>2014>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer the question that follows.  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The diagram is the transverse section of a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">dicotyledonous stem</div>", "<div style=\"font-family:Cambria;font-size:17px;\">monocotyledonous root</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dicotyledonous root</div>", "<div style=\"font-family:Cambria;font-size:17px;\">monocotyledonous stem</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Dicotyledonous root. Dicot Root: <br/> -\tCentral star-shaped xylem. <br/> -\tPhloem between xylem arms. <br/> -\tNo central pith. <br/> -\tEndodermis and pericycle clearly defined. <br/> Monocot Root: <br/> -\tRing of vascular bundles. <br/> -\tCentral pith present. <br/> -\tEndodermis and pericycle surrounding the ring of bundles.</div>", "topic": "INTERNAL STRUCTURE OF A FLOWERING PLANT : STEM"}, {"id": "objective>Biology>2014>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">i<span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">2</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">1</span>, c<span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">0</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">0</span>, pm<span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">3</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">2</span>, m<span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">3</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">3</span>  <br/>  The dental formula above represents that of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a detritus feeder</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a carnivore</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a herbivore</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an omnivore</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The dental formula is that of a herbivore.it is due to the absence of canine</div>", "topic": "NUTRITION : ANIMAL NUTRITION"}, {"id": "objective>Biology>2014>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A circulatory system is very essential in mammals but not in smaller organisms like Amoeba because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">diffusion is sufficient to transport materials in Amoeba</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Amoeba lacks blood containing haemoglobin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Amoeba exhibits anaerobic respiration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Amoeba lives in freshwater</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In smaller organisms like Amoeba, diffusion is sufficient to transport materials. This is because they are single-celled organisms and the distance over which substances need to be transported is small. Therefore, a circulatory system is not necessary. In contrast, mammals are multicellular organisms with specialized cells and tissues, so a circulatory system is needed to transport substances to and from these cells.</div>", "topic": "TRANSPORT : MAMMALIAN CIRCULATORY SYSTEM"}, {"id": "objective>Biology>2014>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In vascular plants, the sieve tubes and companion cells are present in the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cortex</div>", "<div style=\"font-family:Cambria;font-size:17px;\">xylem</div>", "<div style=\"font-family:Cambria;font-size:17px;\">phloem</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cambium</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In vascular plants, the sieve tubes and companion cells are present in the phloem. The phloem is a type of tissue in vascular plants that transports nutrients, such as sugars, from the leaves (where they are produced via photosynthesis) to other parts of the plant. Sieve tubes and companion cells are two types of cells that make up the phloem.</div>", "topic": "TRANSPORT : PLANT VASCULAR SYSTEM"}, {"id": "objective>Biology>2014>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The stomata of leaves are similar in function to the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">scales of fish</div>", "<div style=\"font-family:Cambria;font-size:17px;\">spiracle of insects</div>", "<div style=\"font-family:Cambria;font-size:17px;\">trachea of toads</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pharynx of humans</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The stomata of leaves are similar in function to the spiracles of insects. Both stomata and spiracles are involved in gas exchange. Stomata, found on the surface of leaves, allow for the exchange of gases (carbon dioxide and oxygen) between the plant and the atmosphere. Similarly, spiracles, found in insects, allow for the exchange of gases (oxygen and carbon dioxide) between the insect and the atmosphere.</div>", "topic": "INTERNAL STRUCTURE OF A FLOWERING PLANT : LEAF"}, {"id": "objective>Biology>2014>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The use of moist skin for respiration in amphibians is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cutaneous respiration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">buccal respiration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pulmonary respiration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cellular respiration</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The use of moist skin for respiration in amphibians is known as cutaneous respiration. Cutaneous respiration is a form of respiration where gas exchange occurs across the skin or outer integument of an organism rather than gills or lungs. Amphibians, like frogs, often use this method of respiration, in addition to their lungs, to obtain oxygen.</div>", "topic": "RESPIRATION : THE MECHANISM OF GASEOUS EXCHANGE IN PLANTS AND MAMMALS"}, {"id": "objective>Biology>2014>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Water in plants is removed as water vapour through the process of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">osmosis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">evaporation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">transpiration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">diffusion</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Water in plants is removed as water vapour through the process of transpiration.  <br/> Transpiration is the process by which moisture is carried through plants from roots to small pores on the underside of leaves, where it changes to vapor and is released to the atmosphere. Transpiration is essentially evaporation of water from plant leaves</div>", "topic": "TRANSPORT : MATERIALS FOR TRANSPORTATION"}, {"id": "objective>Biology>2014>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An example of an organ of perennation in plants is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">seed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">petal of a flower</div>", "<div style=\"font-family:Cambria;font-size:17px;\">calyx of flower</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rhizome</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An organ of perennation in plants is a structure that allows a plant to survive an unfavorable season or period (such as winter or drought) and grow again when conditions improve. A rhizome, which is an underground stem, is an example of an organ of perennation. It can store food and water, and produce new shoots to allow the plant to grow again when conditions are favorable.</div>", "topic": "GROWTH : GERMINATION OF SEEDS AND CONDITION NECESSARY FOR GERMINATION OF SEEDS"}, {"id": "objective>Biology>2014>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Alternation of generation is a feature shown in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">fungi</div>", "<div style=\"font-family:Cambria;font-size:17px;\">grasses</div>", "<div style=\"font-family:Cambria;font-size:17px;\">conifers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mosses</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Alternation of generations is a feature shown in mosses. This is a type of life cycle found in terrestrial plants and some algae in which subsequent generations of individuals alternate between haploid and diploid organisms. In mosses, the haploid gametophyte is the dominant generation, while the diploid sporophyte is nutritionally dependent on the gametophyte.</div>", "topic": "EVOLUTION AMONG THE FOLLOWING : PLANTAE"}, {"id": "objective>Biology>2014>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">I. Growth is mainly apical  <br/> II. Growth is specific with definite shape  <br/>  <br/> III. Growth is throughout life  <br/>  Which of the above correctly describes the growth pattern in plants?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">II and III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and II only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">l and Ill only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II and III only</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The growth pattern in plants is characterized two statements. I. Growth is mainly apical: In plants, growth is primarily concentrated at the tips of roots and shoots. This is known as apical growth. III. Growth is throughout life: Unlike animals, plants continue to grow throughout their life. This is due to the presence of meristematic tissue in their tips.</div>", "topic": "GROWTH : MEANING OF GROWTH"}, {"id": "objective>Biology>2014>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Coordination and regulation of body activities in mammals are achieved by the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">nerves and hormones</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nerves only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hormones only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nerves and muscles</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Coordination and regulation of body activities in mammals are achieved by both the nervous system (nerves) and the endocrine system (hormones). The nervous system provides fast, short-term coordination through electrical signals (nerve impulses), while the endocrine system provides slower, long-term coordination through chemicals (hormones) released into the bloodstream.</div>", "topic": "COORDINATION AND CONTROL : HORMONAL CONTROL~~COORDINATION AND CONTROL : NERVOUS COORDINATION"}, {"id": "objective>Biology>2014>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The cerebellum of the brain controls</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">muscular activity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">emotional expressions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the endocrine system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reflex actions</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The cerebellum, a part of the brain, is primarily responsible for regulating and coordinating muscular activity. It plays a crucial role in maintaining posture and balance, ensuring that movements are smooth and coordinated.</div>", "topic": "COORDINATION AND CONTROL : NERVOUS COORDINATION"}, {"id": "objective>Biology>2014>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The part of the brain responsible for peristalsis is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">medulla oblongata</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hypothalamus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">thalamus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">olfactory lobe</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The medulla oblongata is a part of the brain that is responsible for regulating several basic functions of the autonomic nervous system, including peristalsis. Peristalsis is the involuntary constriction and relaxation of the muscles of the intestine or another canal, creating wave-like movements that push the contents of the canal forward.</div>", "topic": "COORDINATION AND CONTROL : NERVOUS COORDINATION"}, {"id": "objective>Biology>2014>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following instruments is used for measuring atmospheric pressure?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Hygrometer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Thermometer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Barometer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hydrometer</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A barometer is an instrument used to measure atmospheric pressure. It can measure the pressure exerted by the atmosphere by balancing it against the force of a column of liquid (usually mercury). The height of the column of liquid is a measure of the atmospheric pressure.</div>", "topic": "N/A"}, {"id": "objective>Biology>2014>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The influence of soil on organisms in a habitat is referred to as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">physiographic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">biotic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">topographic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">edaphic</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The influence of soil on organisms in a habitat is referred to as edaphic. Edaphic refers to soil-related factors, including its physical, chemical, and biological properties. These factors can influence the types of plants that can grow in a particular habitat, which in turn affects the types of animals that can live there.</div>", "topic": "ECOLOGY : FACTORS AFFECTING THE DISTRIBUTION OF ORGANISMS"}, {"id": "objective>Biology>2014>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The genetic make-up of an organism is described as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">chromosome</div>", "<div style=\"font-family:Cambria;font-size:17px;\">phenotype</div>", "<div style=\"font-family:Cambria;font-size:17px;\">genotype</div>", "<div style=\"font-family:Cambria;font-size:17px;\">allele</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The genetic make-up of an organism is described as its genotype. The genotype is the part of the genetic makeup of a cell, and therefore of any individual, which determines one of its characteristics (phenotype). It is one of its genes or a set of genes that is carried by an individual. It does not refer to the entire genetic makeup of an individual, which would include all of its genes, its chromosomes, or its alleles.</div>", "topic": "HEREDITY : CHROMOSOMES"}, {"id": "objective>Biology>2014>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major limiting factor of productivity in the aquatic habitat include the following except?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">temperature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sunlight</div>", "<div style=\"font-family:Cambria;font-size:17px;\">food</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Water is not a limiting factor in aquatic habitats, as it is the medium in which aquatic organisms live. In fact, water is a necessary component of aquatic habitats, and its absence would make life impossible. <br/>  <br/> The other options are all limiting factors in aquatic habitats: <br/>  <br/> Food: The availability of food can limit the growth and survival of aquatic organisms. <br/>  <br/> Temperature: Temperature affects the metabolism and survival of aquatic organisms, and extreme temperatures can be limiting. <br/>  <br/> Sunlight: Sunlight is essential for photosynthesis, and its availability can limit the growth and survival of aquatic plants and algae. <br/>  <br/> Therefore, the correct answer is water</div>", "topic": "ECOLOGY : FACTORS AFFECTING THE DISTRIBUTION OF ORGANISMS"}, {"id": "objective>Biology>2014>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following group of organisms feeds directly on green plants?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Secondary consumers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Producers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Decomposers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Primary consumers</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Primary consumers are the group of organisms that feed directly on green plants. In the food chain, primary consumers are typically herbivores that eat plants and other producers. Secondary consumers, on the other hand, typically eat primary consumers, while decomposers break down dead or decaying organisms. Producers, such as green plants, produce their own food through photosynthesis.</div>", "topic": "ECOLOGY : FOOD CHAINS FOOD WEBS AND TROPHIC LEVELS"}, {"id": "objective>Biology>2014>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A characteristic feature of tropical rainforest is that it</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">contains large number of plant species</div>", "<div style=\"font-family:Cambria;font-size:17px;\">contains fewer number of plant species</div>", "<div style=\"font-family:Cambria;font-size:17px;\">has total annual rainfall of less than 50cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">contains trees with narrow leaves</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Tropical rainforests are known for their biodiversity, which means they contain a large number of different plant species. This is due to the warm, wet climate that allows for a wide variety of plants to grow.</div>", "topic": "LOCAL(NIGERIAN) BIOMES : TROPICAL RAINFOREST"}, {"id": "objective>Biology>2014>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The study of how and why population size change over time is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">population dynamics</div>", "<div style=\"font-family:Cambria;font-size:17px;\">population ecology</div>", "<div style=\"font-family:Cambria;font-size:17px;\">population cycles</div>", "<div style=\"font-family:Cambria;font-size:17px;\">population estimation</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Population dynamics is the branch of life sciences that studies the size and age composition of populations as dynamic systems, and the biological and environmental processes driving them (such as birth and death rates, and by immigration and emigration).</div>", "topic": "THE ECOLOGY OF POPULATIONS : FACTORS AFFECTING POPULATION SIZES"}, {"id": "objective>Biology>2014>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A severe and long dry season is a characteristic feature of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mangrove swamps</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sudan savanna</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Guinea savanna</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sahel savanna</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Sahel savanna is known for its long, severe dry seasons. The Sahel is a transitional ecoregion of semi-arid grasslands, savannas, steppes, and thorn shrublands lying between the wooded Sudan savanna to the south and the Sahara desert to the north.</div>", "topic": "LOCAL(NIGERIAN) BIOMES : SUDAN SAVANNA"}, {"id": "objective>Biology>2014>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a nitrogen-fixing blue-green algae of soil?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Nitrosomonas</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Clostridium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Anabaena</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Rhizobium</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Anabaena is a genus of filamentous cyanobacteria, or blue-green algae, that is known for its nitrogen-fixing abilities. Nitrogen fixation is a process by which nitrogen in the atmosphere is converted into a form that can be used by plants. Nitrosomonas, Clostridium, and Rhizobium, while they are all involved in the nitrogen cycle, they are not blue-green algae.</div>", "topic": "NUTRITION : PLANT NUTRITION"}, {"id": "objective>Biology>2014>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The soil with the highest water-retaining capacity is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">stoney soil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sandy soil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">loamy soil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">clayey soil</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Clayey soil has the highest water-retaining capacity among the options given. This is due to its fine texture and compactness, which allows it to hold water better than sandy, loamy, or stoney soils. Sandy soil has the least water-retaining capacity because of its coarse texture and large particles, which allow water to drain quickly. Loamy soil has a balance of sand, silt, and clay, and while it retains water well, it does not retain as much as clayey soil. Stoney soil, as the name suggests, contains a lot of stones, which do not retain water well.</div>", "topic": "SOIL : CHARACTERISTICS OF DIFFERENT TYPES OF SOIL"}, {"id": "objective>Biology>2014>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The causative agent of poliomyelitis is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">fungus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">protozoan</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bacterium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">virus</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Poliomyelitis, also known as polio, is caused by the poliovirus. A virus is a small infectious agent that can only replicate inside the living cells of an organism. Fungi, protozoans, and bacteria are all different types of microorganisms, but they do not cause poliomyelitis.</div>", "topic": "HUMANS AND ENVIRONMENT : DISEASES"}, {"id": "objective>Biology>2014>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the ways of controlling noise pollution in urban areas is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">that fuel should be completely combusted by engines</div>", "<div style=\"font-family:Cambria;font-size:17px;\">by planting trees on both sides of the road</div>", "<div style=\"font-family:Cambria;font-size:17px;\">by wearing ear devices</div>", "<div style=\"font-family:Cambria;font-size:17px;\">by siting industries away from residential areas</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Noise pollution in urban areas can be controlled by siting industries away from residential areas. This is because industries are a major source of noise pollution due to the heavy machinery and processes they use. By siting them away from residential areas, the impact of this noise on people's daily lives can be reduced.</div>", "topic": "HUMANS AND ENVIRONMENT : POLLUTION AND ITS CONTROL"}, {"id": "objective>Biology>2014>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A constituent of the exhaust fumes from electricity generating sets which causes serious air pollution is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">water vapour</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ozone</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbon (IV) oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbon (II) oxide</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Carbon (II) oxide, also known as carbon monoxide, is a major pollutant that is released from the exhaust fumes of electricity generating sets. It is a colorless, odorless, and poisonous gas that is produced from the incomplete combustion of carbon-containing fuels. When inhaled, it can interfere with the blood's ability to carry oxygen, leading to serious health effects.</div>", "topic": "HUMANS AND ENVIRONMENT : POLLUTION AND ITS CONTROL"}, {"id": "objective>Biology>2014>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is true of small pox?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">It can effectively he controlled with antibiotics</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It can effectively be controlled by vaccination</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It is a water-borne infection</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It is transmitted by bacteria</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Smallpox can effectively be controlled by vaccination. Smallpox is a viral disease, and antibiotics, which are used to treat bacterial infections, are ineffective against it. Vaccination works by stimulating the body's immune system to recognize and fight the smallpox virus, thereby preventing the disease.</div>", "topic": "HUMANS AND ENVIRONMENT : DISEASES"}, {"id": "objective>Biology>2014>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A pollutant that is mostly associated with acid rain is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ozone</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fluorine</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbon(IV)oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nitrogen(IV)oxide</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Acid rain is primarily caused by emissions of sulfur dioxide and nitrogen oxide from various human activities such as industrial processes and vehicle exhaust. These gases react in the atmosphere with water, oxygen, and other chemicals to form various acidic compounds. Nitrogen(IV)oxide is one of these gases, hence it is associated with acid rain.</div>", "topic": "HUMANS AND ENVIRONMENT : POLLUTION AND ITS CONTROL"}, {"id": "objective>Biology>2014>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When the adults have reached a certain degree of weakness, the process of binary fission is replaced by conjugation in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Euglena</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Amoeba</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Plasmodium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Paramecium</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Conjugation is a form of sexual reproduction in unicellular organisms. In Paramecium, when the adults have reached a certain degree of weakness, the process of binary fission (asexual reproduction) is replaced by conjugation. During conjugation, two paramecia come together and exchange genetic material, then separate and divide to form new individuals.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>2014>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Whorls, arches, loops and compounds are types of variation in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">fingerprints</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hair colour</div>", "<div style=\"font-family:Cambria;font-size:17px;\">blood group</div>", "<div style=\"font-family:Cambria;font-size:17px;\">eye colour</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Whorls, arches, loops and compounds are types of patterns found in fingerprints. These patterns are unique to each individual and are used for identification purposes. The study of these patterns is called dermatoglyphics.</div>", "topic": "VARIATION IN POPULATION : MORPHOLOGICAL VARIATIONS"}, {"id": "objective>Biology>2014>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A couple has 10 children, all female. Which of the following best explains the situation?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The man's sperm count is low</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The woman is not capable of producing male children</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The sex determination was by the man's Y chromosome</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The sex determination was by the man's X chromosome</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The sex of a child is determined by the type of sperm that fertilizes the woman's egg. A sperm can either carry an X or a Y chromosome. If the sperm carrying an X chromosome fertilizes the egg, the child will be female (XX). If the sperm carrying a Y chromosome fertilizes the egg, the child will be male (XY). Therefore, if all the children are female, it means that all the fertilizing sperms carried X chromosomes.</div>", "topic": "HEREDITY : SEX-LINKED CHARACTERS"}, {"id": "objective>Biology>2014>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A biological agent with antiviral property is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">enzyme</div>", "<div style=\"font-family:Cambria;font-size:17px;\">antibiotic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">disinfectant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">interferon</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Interferons are proteins produced by the body's immune system in response to viruses. They have antiviral properties and work by interfering with the replication of viruses. Enzymes, antibiotics, and disinfectants do not have antiviral properties. Antibiotics are used to treat bacterial infections, not viral infections. Disinfectants are used to kill or inactivate microorganisms on inanimate objects and surfaces.</div>", "topic": "HUMANS AND ENVIRONMENT : DISEASES"}, {"id": "objective>Biology>2014>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the advantages of outbreeding is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">disease resistance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fast growth</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tall height</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pests tolerance</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Outbreeding, or outcrossing, is the practice of introducing unrelated genetic material into a breeding line. This has the advantage of increasing genetic diversity, which can lead to greater disease resistance. Disease resistance is a desirable trait because it can increase survival and reproduction rates. Fast growth, tall height, and pests tolerance are not necessarily advantages of outbreeding.</div>", "topic": "HEREDITY : APPLICATION OF THE PRINCIPLES OF HEREDITY"}, {"id": "objective>Biology>2014>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An individual with blood group AB can receive blood from those in blood group(s)</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">A, AB and O only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">AB only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A and B only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A, B, AB and O</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An individual with blood group AB is a universal recipient. This means they can receive blood from individuals of any blood group: A, B, AB, or O. This is because their blood does not have any antibodies against A, B or O antigens.</div>", "topic": "TRANSPORT : MAMMALIAN CIRCULATORY SYSTEM"}, {"id": "objective>Biology>2014>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The stream-lined shape of fishes is an adaptation for</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">easy movement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">obtaining food</div>", "<div style=\"font-family:Cambria;font-size:17px;\">defence and attack</div>", "<div style=\"font-family:Cambria;font-size:17px;\">securing mates</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The streamlined shape of fishes is an adaptation for easy movement. This shape reduces the resistance of water, allowing the fish to move quickly and efficiently through their aquatic environment.</div>", "topic": "ADAPTATION FOR SURVIVAL : ADAPTIVE COLOURATION AND ITS FUNCTIONS"}, {"id": "objective>Biology>2014>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An example of a poikilothermic organism is a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cockroach</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rabbit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bird</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lizard</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A poikilothermic organism, also known as a cold-blooded organism, is one that does not have an internal mechanism to regulate its body temperature. Instead, its body temperature changes with the environment. Examples of poikilothermic organisms include reptiles, amphibians, and fish. Among the options given, the lizard is a poikilothermic organism.</div>", "topic": "ADAPTATION FOR SURVIVAL : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS"}, {"id": "objective>Biology>2014>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">All living organisms are constantly involved in a struggle for existence. This was proposed by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Darwin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lamarck</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Wallace</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Morgan</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The concept of 'struggle for existence' was proposed by Charles Darwin. It is a part of his theory of natural selection, where he proposed that all living organisms are constantly involved in a struggle for existence, and only the fittest survive this struggle.</div>", "topic": "ADAPTATION FOR SURVIVAL : COMPETITION"}, {"id": "objective>Biology>2014>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Adaptive radiation is illustrated in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">dentition in mammals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">wings in birds and bats</div>", "<div style=\"font-family:Cambria;font-size:17px;\">appendages in insects</div>", "<div style=\"font-family:Cambria;font-size:17px;\">modified insect mouthparts</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Adaptive radiation is illustrated in wings in modified insect mouthparts. Adaptive radiation is an evolutionary process where organisms diversify rapidly into a multitude of new forms, particularly when a change in the environment makes new resources available, creates new challenges, or opens new environmental niches. </div>", "topic": "EVOLUTION : THEORIES OF EVOLUTION"}];
